import { reactive } from 'vue';
import { fetchFormPageRows } from '../api/form';

export function useFormPage() {
  const state = reactive({
    searchForm: {},
    rows: [],
    loading: false,
  });

  async function search() {
    state.loading = true;
    try {
      state.rows = await fetchFormPageRows(state.searchForm);
    } finally {
      state.loading = false;
    }
  }

  return {
    state,
    actions: { search },
    meta: {
      primaryDatasetId: 'ds_scorechk',
      searchDatasetId: '',
    },
  };
}

export default useFormPage;

export async function fetchFormPageRows(searchForm: Record<string, unknown>) {
  const response = await fetch('/api/form/search', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(searchForm),
  });

  if (!response.ok) {
    throw new Error('Failed to fetch data for form');
  }

  return response.json();
}

export const targetRoute = '/form';

